import React, { useState, useEffect } from 'react';
import API from '../services/api';

export default function CreateJob(){
  const [cars,setCars]=useState([]);
  const [carId,setCarId]=useState('');
  const [complaint,setComplaint]=useState('');

  useEffect(()=>{
    async function load(){ try{ const res = await API.get('/cars/my'); setCars(res.data); }catch(e){ console.error(e); } }
    load();
  },[]);

  async function submit(e){
    e.preventDefault();
    try{
      await API.post('/jobs', { customer: null, car: carId, complaint, customerPhone: null });
      alert('Job created');
    }catch(e){ alert('Error creating job'); }
  }

  return (
    <div style={{padding:20}}>
      <h2>Create Service Request</h2>
      <form onSubmit={submit}>
        <select value={carId} onChange={e=>setCarId(e.target.value)}>
          <option value=''>Select car</option>
          {cars.map(c=> <option key={c._id} value={c._id}>{c.model} - {c.regNo}</option>)}
        </select><br/>
        <textarea placeholder='Describe issue' value={complaint} onChange={e=>setComplaint(e.target.value)} /><br/>
        <button>Create Job</button>
      </form>
    </div>
  );
}
